package Core_java;
//Relational operators are used for comparasion between the operands and return type is boolean
public class Relational_op {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a=20,b=10;//operands                        
		System.out.println(a>b);
		System.out.println(a<b);
		System.out.println(a<=b);
		System.out.println(a>=b);
		System.out.println(a==b);
		System.out.println(a!=b);
	}
}
                                                                                                                             